internal final class UBSTriggerDimensionDefaultingService extends SysOperationServiceBase
{
}

Method.Source:
    public void Process(UBSTriggerDimensionDefaultingContract _dimensionContract)
    {
        UBSVendorDimensionToSync    vendorDimensionToSync;
        DataArea                    dataArea;

        while select forupdate vendorDimensionToSync
            where !vendorDimensionToSync.UBSDimensionIsUpdated
        {
            while select id from dataArea
                where dataArea.id != _dimensionContract.parmLegalEntity()
            {
                changecompany(dataArea.id)
                {
                    VendTable  vendTable = VendTable::find(vendorDimensionToSync.UBSAccountNum,true);

                    if(vendTable)
                    {
                        ttsbegin;
                        DimensionDefaultFacade::copyDimensionValueToDefaultDimensionField(vendTable, fieldNum(VendTable, AccountNum), vendTable, fieldNum(VendTable, DefaultDimension));
                        ttscommit;
                    }
                }
            }

            ttsbegin;
            vendorDimensionToSync.UBSDimensionIsUpdated = NoYes::Yes;
            vendorDimensionToSync.update();
            ttscommit;
        }
    }
